-- Verification queries
-- ============================================================
SELECT COUNT(*) AS total_matches FROM public.matches;

SELECT COUNT(*) AS missing_stadium FROM public.matches WHERE stadium_name IS NULL;

SELECT COUNT(*) AS missing_match_number FROM public.matches WHERE match_number IS NULL;

SELECT stage, COUNT(*) AS n FROM public.matches GROUP BY stage ORDER BY stage;

-- Group stage team ID check (should return 0)
SELECT COUNT(*) AS group_missing_team_ids FROM public.matches
WHERE stage = 'GROUP' AND (home_team_id IS NULL OR away_team_id IS NULL);

-- Sample of all data
SELECT match_number, stage, group_letter, home_team, away_team, stadium_name, city, country, kickoff_at
FROM public.matches ORDER BY match_number LIMIT 20;